const LOGO = "data:image/jpeg;base64,";
const fmt = n => { if (n == null || isNaN(n)) return "0"; if (Math.abs(n) >= 1e6) return (n / 1e6).toFixed(1).replace(".", ",") + "M"; if (Math.abs(n) >= 1e3) return Math.round(n).toLocaleString("cs-CZ"); return String(Math.round(n)); };
const fK = n => fmt(n) + " Kč";
const comp = (b, r, y) => b * Math.pow(1 + r / 100, y);
const toYr = (v, u) => { const n = Number(v) || 0; return u === "czk_m" ? n * 12 : n; };
const fvSav = (pv, pmt, r, n) => { if (r === 0) return pv + pmt * n; const rv = r / 100; return pv * Math.pow(1 + rv, n) + pmt * (Math.pow(1 + rv, n) - 1) / rv; };

